import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler,
} from "chart.js";
import { getAllStocks } from "../services/stockService";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

export default function Dashboard() {
  const [stocks, setStocks] = useState([]);
  const [portfolioValue, setPortfolioValue] = useState(0);
  const [todayChange, setTodayChange] = useState(0);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const allStocks = await getAllStocks();
      setStocks(allStocks.slice(0, 5));
      
      // Load portfolio
      const portfolio = JSON.parse(localStorage.getItem("portfolio") || "[]");
      let totalValue = 0;
      let invested = 0;
      
      portfolio.forEach(item => {
        const stock = allStocks.find(s => s.symbol === item.symbol);
        if (stock) {
          totalValue += stock.price * item.quantity;
          invested += item.avgPrice * item.quantity;
        }
      });
      
      setPortfolioValue(totalValue);
      setTodayChange(totalValue - invested);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setLoading(false);
    }
  };

  const chartData = {
    labels: ["Jan", "Feb", "Mar", "Apr", "May", "Jun"],
    datasets: [
      {
        label: "Portfolio Value",
        data: [100000, 105000, 98000, 112000, 108000, 125000],
        fill: true,
        borderColor: "#4f46e5",
        backgroundColor: "rgba(79, 70, 229, 0.1)",
        tension: 0.4,
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        display: false,
      },
    },
    scales: {
      x: {
        grid: {
          display: false,
        },
      },
      y: {
        grid: {
          color: "rgba(0, 0, 0, 0.05)",
        },
      },
    },
  };

  const marketOverview = {
    sensex: { value: 73500, change: 250.5, changePercent: 0.34 },
    nifty: { value: 22150, change: 75.2, changePercent: 0.34 },
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        <h1 className="text-3xl font-bold text-gray-800 mb-6">Dashboard</h1>

        {/* Portfolio Summary Cards */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
          <div className="bg-white rounded-xl shadow-md p-6 border-l-4 border-indigo-600">
            <p className="text-sm text-gray-500 mb-1">Total Portfolio Value</p>
            <p className="text-2xl font-bold text-gray-800">₹{portfolioValue.toLocaleString('en-IN') || 0}</p>
            <p className="text-sm text-gray-500 mt-2">+₹0 from yesterday</p>
          </div>
          
          <div className="bg-white rounded-xl shadow-md p-6 border-l-4 border-green-500">
            <p className="text-sm text-gray-500 mb-1">Today's P&L</p>
            <p className={`text-2xl font-bold ${todayChange >= 0 ? "text-green-600" : "text-red-600"}`}>
              {todayChange >= 0 ? "+" : ""}₹{todayChange.toLocaleString('en-IN') || 0}
            </p>
            <p className="text-sm text-gray-500 mt-2">{todayChange >= 0 ? "Profit" : "Loss"}</p>
          </div>
          
          <div className="bg-white rounded-xl shadow-md p-6 border-l-4 border-blue-500">
            <p className="text-sm text-gray-500 mb-1">Holdings</p>
            <p className="text-2xl font-bold text-gray-800">{JSON.parse(localStorage.getItem("portfolio") || "[]").length}</p>
            <p className="text-sm text-gray-500 mt-2">Active stocks</p>
          </div>
          
          <div className="bg-white rounded-xl shadow-md p-6 border-l-4 border-yellow-500">
            <p className="text-sm text-gray-500 mb-1">Watchlist</p>
            <p className="text-2xl font-bold text-gray-800">{JSON.parse(localStorage.getItem("watchlist") || "[]").length}</p>
            <p className="text-sm text-gray-500 mt-2">Saved stocks</p>
          </div>
        </div>

        {/* Charts Row */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
          {/* Portfolio Chart */}
          <div className="bg-white rounded-xl shadow-md p-6 lg:col-span-2">
            <h2 className="text-xl font-bold text-gray-800 mb-4">Portfolio Performance</h2>
            <div className="h-64">
              <Line data={chartData} options={chartOptions} />
            </div>
          </div>

          {/* Market Indices */}
          <div className="bg-white rounded-xl shadow-md p-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4">Market Overview</h2>
            <div className="space-y-4">
              <div className="p-4 bg-gray-50 rounded-lg">
                <div className="flex justify-between items-center">
                  <div>
                    <p className="text-sm text-gray-600">SENSEX</p>
                    <p className="text-xl font-bold text-gray-800">{marketOverview.sensex.value.toLocaleString('en-IN')}</p>
                  </div>
                  <div className="text-right">
                    <p className={`font-semibold ${marketOverview.sensex.change >= 0 ? "text-green-600" : "text-red-600"}`}>
                      {marketOverview.sensex.change >= 0 ? "+" : ""}{marketOverview.sensex.change}
                    </p>
                    <p className={`text-sm ${marketOverview.sensex.changePercent >= 0 ? "text-green-600" : "text-red-600"}`}>
                      ({marketOverview.sensex.changePercent >= 0 ? "+" : ""}{marketOverview.sensex.changePercent}%)
                    </p>
                  </div>
                </div>
              </div>
              
              <div className="p-4 bg-gray-50 rounded-lg">
                <div className="flex justify-between items-center">
                  <div>
                    <p className="text-sm text-gray-600">NIFTY 50</p>
                    <p className="text-xl font-bold text-gray-800">{marketOverview.nifty.value.toLocaleString('en-IN')}</p>
                  </div>
                  <div className="text-right">
                    <p className={`font-semibold ${marketOverview.nifty.change >= 0 ? "text-green-600" : "text-red-600"}`}>
                      {marketOverview.nifty.change >= 0 ? "+" : ""}{marketOverview.nifty.change}
                    </p>
                    <p className={`text-sm ${marketOverview.nifty.changePercent >= 0 ? "text-green-600" : "text-red-600"}`}>
                      ({marketOverview.nifty.changePercent >= 0 ? "+" : ""}{marketOverview.nifty.changePercent}%)
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Top Movers & Quick Actions */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Top Gainers */}
          <div className="bg-white rounded-xl shadow-md p-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4">Top Gainers</h2>
            <div className="space-y-3">
              {stocks.filter(s => s.change > 0).slice(0, 5).map((stock) => (
                <Link
                  key={stock.symbol}
                  to={`/stock/${stock.symbol}`}
                  className="flex items-center justify-between p-3 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  <div>
                    <p className="font-semibold text-gray-800">{stock.symbol}</p>
                    <p className="text-sm text-gray-500">{stock.name}</p>
                  </div>
                  <div className="text-right">
                    <p className="font-semibold text-gray-800">₹{stock.price.toLocaleString('en-IN')}</p>
                    <p className="text-sm text-green-600">+{stock.changePercent.toFixed(2)}%</p>
                  </div>
                </Link>
              ))}
            </div>
          </div>

          {/* Top Losers */}
          <div className="bg-white rounded-xl shadow-md p-6">
            <h2 className="text-xl font-bold text-gray-800 mb-4">Top Losers</h2>
            <div className="space-y-3">
              {stocks.filter(s => s.change < 0).slice(0, 5).map((stock) => (
                <Link
                  key={stock.symbol}
                  to={`/stock/${stock.symbol}`}
                  className="flex items-center justify-between p-3 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  <div>
                    <p className="font-semibold text-gray-800">{stock.symbol}</p>
                    <p className="text-sm text-gray-500">{stock.name}</p>
                  </div>
                  <div className="text-right">
                    <p className="font-semibold text-gray-800">₹{stock.price.toLocaleString('en-IN')}</p>
                    <p className="text-sm text-red-600">{stock.changePercent.toFixed(2)}%</p>
                  </div>
                </Link>
              ))}
            </div>
          </div>
        </div>

        {/* Quick Actions */}
        <div className="mt-8 bg-gradient-to-r from-indigo-600 to-purple-600 rounded-xl shadow-lg p-6 text-white">
          <h2 className="text-2xl font-bold mb-4">Quick Actions</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <Link
              to="/markets"
              className="bg-white bg-opacity-20 rounded-lg p-4 text-center hover:bg-opacity-30 transition-colors"
            >
              <svg className="w-8 h-8 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" />
              </svg>
              <p className="font-semibold">Explore Stocks</p>
            </Link>
            <Link
              to="/portfolio"
              className="bg-white bg-opacity-20 rounded-lg p-4 text-center hover:bg-opacity-30 transition-colors"
            >
              <svg className="w-8 h-8 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
              </svg>
              <p className="font-semibold">View Portfolio</p>
            </Link>
            <Link
              to="/watchlist"
              className="bg-white bg-opacity-20 rounded-lg p-4 text-center hover:bg-opacity-30 transition-colors"
            >
              <svg className="w-8 h-8 mx-auto mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" />
              </svg>
              <p className="font-semibold">My Watchlist</p>
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}
